import { useEffect, useMemo, useState } from 'react';
import type { SelectOption } from '@linm-soft-org/linm-web-common-components';
import { voucherInitService, type ErpFormInitData } from '../services/voucherInit/endpoint';

const EMPTY: SelectOption[] = [];
const toOpts = (items?: FormOption[]): SelectOption[] =>
  (items ?? []).map(o => ({ value: o.value, label: o.label }));

type FormOption = { value: string; label: string };

export function useVoucherInitData(formName: string) {
  const [data, setData] = useState<ErpFormInitData | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    let cancelled = false;
    setLoading(true);
    const timer = setTimeout(() => {
      if (cancelled) return;
      voucherInitService
        .getInitData(formName)
        .then(d => { if (!cancelled) setData(d); })
        .catch(() => { /* non-blocking — empty dropdowns */ })
        .finally(() => { if (!cancelled) setLoading(false); });
    }, 0);
    return () => { cancelled = true; clearTimeout(timer); };
  }, [formName]);

  const materialGroupOptions = useMemo(
    () => toOpts(data?.materialGroupOptions),
    [data?.materialGroupOptions],
  );
  const customerGroupOptions = useMemo(
    () => toOpts(data?.customerGroupOptions),
    [data?.customerGroupOptions],
  );
  const unitOptions = useMemo(() => toOpts(data?.unitOptions), [data?.unitOptions]);
  const taxRateOptions = useMemo(() => toOpts(data?.taxRateOptions), [data?.taxRateOptions]);
  const currencyOptions = useMemo(() => toOpts(data?.currencyOptions), [data?.currencyOptions]);
  const warehouseOptions = useMemo(() => toOpts(data?.warehouseOptions), [data?.warehouseOptions]);
  const departmentOptions = useMemo(
    () => toOpts(data?.departmentOptions),
    [data?.departmentOptions],
  );
  const voucherStatusOptions = useMemo(
    () => toOpts(data?.voucherStatusOptions),
    [data?.voucherStatusOptions],
  );
  const purchaseInvoiceTypeOptions = useMemo(
    () => toOpts(data?.purchaseInvoiceTypeOptions),
    [data?.purchaseInvoiceTypeOptions],
  );
  const processingLevelOptions = useMemo(
    () => toOpts(data?.processingLevelOptions),
    [data?.processingLevelOptions],
  );
  const activeStatusOptions = useMemo(
    () => toOpts(data?.activeStatusOptions),
    [data?.activeStatusOptions],
  );
  const customerTypeOptions = useMemo(
    () => toOpts(data?.customerTypeOptions),
    [data?.customerTypeOptions],
  );
  const paymentMethodOptions = useMemo(
    () => toOpts(data?.paymentMethodOptions),
    [data?.paymentMethodOptions],
  );
  const legalTypeOptions = useMemo(
    () => toOpts(data?.legalTypeOptions),
    [data?.legalTypeOptions],
  );
  const vatRegisteredOptions = useMemo(
    () => toOpts(data?.vatRegisteredOptions),
    [data?.vatRegisteredOptions],
  );
  const customerBankAccountKindOptions = useMemo(
    () => toOpts(data?.customerBankAccountKindOptions),
    [data?.customerBankAccountKindOptions],
  );

  return {
    loading,
    materialGroupOptions,
    customerGroupOptions,
    unitOptions,
    taxRateOptions,
    currencyOptions,
    warehouseOptions,
    departmentOptions,
    voucherStatusOptions,
    purchaseInvoiceTypeOptions,
    processingLevelOptions,
    activeStatusOptions,
    customerTypeOptions,
    paymentMethodOptions,
    legalTypeOptions,
    vatRegisteredOptions,
    customerBankAccountKindOptions,
    raw: data,
  };
}
