import React from 'react';
import { Checkbox, Input, MoneyInput, Select, type SelectOption } from '@linm-soft-org/linm-web-common-components';
import type { CustomerFormState } from './useCustomerForm';
import type {
  CustomerBankAccountLine,
  CustomerDiscountTermLine,
} from '../../../services/master/customerDetailModels';
import { CustomerBankAccountGrid, CustomerDiscountTermGrid } from './CustomerDetailGrids';
import styles from './CustomerDetailGrids.module.css';
import pageStyles from '../../../styles/erpPage.module.css';
import { selectPlaceholderClass } from '../../../utils/selectField';

type CustomerSupplierEditSectionProps = {
  testIdPrefix: string;
  form: CustomerFormState;
  setForm: (updater: CustomerFormState | ((prev: CustomerFormState) => CustomerFormState)) => void;
  markDirty: () => void;
  bankLines: CustomerBankAccountLine[];
  discountLines: CustomerDiscountTermLine[];
  onBankLinesChange: (rows: CustomerBankAccountLine[]) => void;
  onDiscountLinesChange: (rows: CustomerDiscountTermLine[]) => void;
  supplierCustomerId?: string;
  paymentMethodOptions: SelectOption[];
  legalTypeOptions: SelectOption[];
  vatRegisteredOptions: SelectOption[];
  bankKindOptions: SelectOption[];
};

export const CustomerSupplierEditSection: React.FC<CustomerSupplierEditSectionProps> = ({
  testIdPrefix,
  form,
  setForm,
  markDirty,
  bankLines,
  discountLines,
  onBankLinesChange,
  onDiscountLinesChange,
  supplierCustomerId,
  paymentMethodOptions,
  legalTypeOptions,
  vatRegisteredOptions,
  bankKindOptions,
}) => {
  const patch = (fields: Partial<CustomerFormState>) => {
    markDirty();
    setForm(f => ({ ...f, ...fields }));
  };

  const vatSelectValue =
    form.vatRegistered === true ? 'true' : form.vatRegistered === false ? 'false' : '';

  return (
    <div data-testid={`${testIdPrefix}-supplier-edit`}>
      <h4 className={styles.sectionTitle}>Thông tin chung (NCC)</h4>
      <div className={pageStyles.formGrid}>
        <div
          className={`${pageStyles.formGridFullRow} ${pageStyles.field}`}
          data-testid={`${testIdPrefix}-field-shortName`}
        >
          <label className={pageStyles.label}>Tên thường gọi</label>
          <Input
            value={form.shortName ?? ''}
            onChange={e => patch({ shortName: e.target.value })}
          />
        </div>
        <div className={pageStyles.field} data-testid={`${testIdPrefix}-field-goodsServiceType`}>
          <label className={pageStyles.label}>Loại hàng hóa / DV</label>
          <Input
            value={form.goodsServiceType ?? ''}
            onChange={e => patch({ goodsServiceType: e.target.value })}
          />
        </div>
        <div className={pageStyles.field} data-testid={`${testIdPrefix}-field-mainIndustry`}>
          <label className={pageStyles.label}>Ngành hàng chính</label>
          <Input
            value={form.mainIndustry ?? ''}
            onChange={e => patch({ mainIndustry: e.target.value })}
          />
        </div>
        <div className={pageStyles.field} data-testid={`${testIdPrefix}-field-email`}>
          <label className={pageStyles.label}>Email</label>
          <Input value={form.email ?? ''} onChange={e => patch({ email: e.target.value })} />
        </div>
        <div className={pageStyles.field} data-testid={`${testIdPrefix}-field-contactPerson`}>
          <label className={pageStyles.label}>Người liên hệ</label>
          <Input
            value={form.contactPerson ?? ''}
            onChange={e => patch({ contactPerson: e.target.value })}
          />
        </div>
        <div className={pageStyles.field} data-testid={`${testIdPrefix}-field-paymentMethod`}>
          <label className={pageStyles.label}>Hình thức thanh toán</label>
          <Select
            value={form.paymentMethod ?? ''}
            placeholder="— Chọn —"
            className={selectPlaceholderClass(form.paymentMethod)}
            onChange={e => patch({ paymentMethod: e.target.value || undefined })}
            options={paymentMethodOptions}
          />
        </div>
        <div className={pageStyles.field} data-testid={`${testIdPrefix}-field-paymentTermDays`}>
          <label className={pageStyles.label}>Tuổi nợ (ngày)</label>
          <Input
            type="number"
            min={0}
            value={form.paymentTermDays != null ? String(form.paymentTermDays) : ''}
            onChange={e => {
              const raw = e.target.value.trim();
              patch({ paymentTermDays: raw === '' ? undefined : Math.max(0, Number(raw) || 0) });
            }}
          />
        </div>
        <div className={pageStyles.field} data-testid={`${testIdPrefix}-field-gracePeriodDays`}>
          <label className={pageStyles.label}>Thời gian GH (ngày)</label>
          <Input
            type="number"
            min={0}
            value={form.gracePeriodDays != null ? String(form.gracePeriodDays) : ''}
            onChange={e => {
              const raw = e.target.value.trim();
              patch({ gracePeriodDays: raw === '' ? undefined : Math.max(0, Number(raw) || 0) });
            }}
          />
        </div>
        <div className={pageStyles.field} data-testid={`${testIdPrefix}-field-documentType`}>
          <label className={pageStyles.label}>Loại chứng từ</label>
          <Input
            value={form.documentType ?? ''}
            onChange={e => patch({ documentType: e.target.value })}
          />
        </div>
        <div className={pageStyles.field} data-testid={`${testIdPrefix}-field-legalType`}>
          <label className={pageStyles.label}>Loại pháp nhân</label>
          <Select
            value={form.legalType ?? ''}
            placeholder="— Chọn —"
            className={selectPlaceholderClass(form.legalType)}
            onChange={e => patch({ legalType: e.target.value || undefined })}
            options={legalTypeOptions}
          />
        </div>
        <div className={pageStyles.field} data-testid={`${testIdPrefix}-field-vatRegistered`}>
          <label className={pageStyles.label}>Đăng ký VAT</label>
          <Select
            value={vatSelectValue}
            placeholder="— Chọn —"
            className={selectPlaceholderClass(vatSelectValue)}
            onChange={e => {
              const v = e.target.value;
              patch({
                vatRegistered: v === 'true' ? true : v === 'false' ? false : undefined,
              });
            }}
            options={vatRegisteredOptions}
          />
        </div>
        <div className={pageStyles.field} data-testid={`${testIdPrefix}-field-creditLimit`}>
          <label className={pageStyles.label}>Hạn mức công nợ</label>
          <MoneyInput
            value={form.creditLimit ?? 0}
            onChange={v => patch({ creditLimit: v })}
          />
        </div>
        <div className={pageStyles.field} data-testid={`${testIdPrefix}-field-district`}>
          <label className={pageStyles.label}>Quận / huyện</label>
          <Input value={form.district ?? ''} onChange={e => patch({ district: e.target.value })} />
        </div>
        <div className={pageStyles.field} data-testid={`${testIdPrefix}-field-province`}>
          <label className={pageStyles.label}>Tỉnh / thành phố</label>
          <Input value={form.province ?? ''} onChange={e => patch({ province: e.target.value })} />
        </div>
        <div className={pageStyles.field} data-testid={`${testIdPrefix}-field-accountingPhone`}>
          <label className={pageStyles.label}>Điện thoại kế toán</label>
          <Input
            value={form.accountingPhone ?? ''}
            onChange={e => patch({ accountingPhone: e.target.value })}
          />
        </div>
        <div className={pageStyles.field} data-testid={`${testIdPrefix}-field-reconciliationEmail`}>
          <label className={pageStyles.label}>Email đối chiếu công nợ</label>
          <Input
            value={form.reconciliationEmail ?? ''}
            onChange={e => patch({ reconciliationEmail: e.target.value })}
          />
        </div>
        <div className={pageStyles.field} data-testid={`${testIdPrefix}-field-salesContactName`}>
          <label className={pageStyles.label}>Tên saler</label>
          <Input
            value={form.salesContactName ?? ''}
            onChange={e => patch({ salesContactName: e.target.value })}
          />
        </div>
        <div className={pageStyles.field} data-testid={`${testIdPrefix}-field-salesContactPhone`}>
          <label className={pageStyles.label}>Điện thoại saler</label>
          <Input
            value={form.salesContactPhone ?? ''}
            onChange={e => patch({ salesContactPhone: e.target.value })}
          />
        </div>
        <div
          className={`${pageStyles.formGridFullRow} ${pageStyles.field}`}
          data-testid={`${testIdPrefix}-field-notes`}
        >
          <label className={pageStyles.label}>Ghi chú</label>
          <Input value={form.notes ?? ''} onChange={e => patch({ notes: e.target.value })} />
        </div>
      </div>

      <h4 className={styles.sectionTitle}>Hợp đồng &amp; chiết khấu theo thời gian</h4>
      <p className={styles.sectionHint}>
        Mỗi dòng = một khoảng chiết khấu gắn hợp đồng NCC. Chọn HĐ từ danh mục hoặc nhập số HĐ mới (tạo khi Lưu).
      </p>
      <CustomerDiscountTermGrid
        rows={discountLines}
        viewOnly={false}
        onChange={onDiscountLinesChange}
        testIdPrefix={testIdPrefix}
        supplierCustomerId={supplierCustomerId}
      />

      <h4 className={styles.sectionTitle}>Thông tin chuyển khoản</h4>
      <CustomerBankAccountGrid
        rows={bankLines}
        viewOnly={false}
        onChange={onBankLinesChange}
        testIdPrefix={testIdPrefix}
        bankKindOptions={bankKindOptions}
      />
    </div>
  );
};
