import { normalizeCode } from '../../utils/codeField';
import type {
  CreateCustomerGroupRequest,
  CustomerGroupDto,
  UpdateCustomerGroupRequest,
} from './models';

function resolveGroupLevel(form: Partial<CustomerGroupDto>): number {
  if (form.level != null && form.level > 0) return form.level;
  return form.parentCustomerGroupId ? 2 : 1;
}

export function toCreateCustomerGroupPayload(
  form: Partial<CustomerGroupDto>,
): CreateCustomerGroupRequest {
  const level = resolveGroupLevel(form);
  const payload: CreateCustomerGroupRequest = {
    code: normalizeCode(form.code!),
    name: form.name!.trim(),
    parentId: form.parentCustomerGroupId || undefined,
    customerType: form.customerType ?? 'Both',
  };
  if (level === 1 && form.formatCode?.trim()) {
    payload.formatCode = normalizeCode(form.formatCode);
  }
  return payload;
}

export function toUpdateCustomerGroupPayload(
  form: Partial<CustomerGroupDto>,
): UpdateCustomerGroupRequest {
  const level = resolveGroupLevel(form);
  const payload: UpdateCustomerGroupRequest = {
    name: form.name!.trim(),
    parentId: form.parentCustomerGroupId || undefined,
    isActive: form.isActive ?? true,
    customerType: form.customerType ?? 'Both',
  };
  if (level === 1 && form.formatCode?.trim()) {
    payload.formatCode = normalizeCode(form.formatCode);
  }
  return payload;
}
