import { normalizeCode, normalizeCodeOptional } from '../../utils/codeField';
import type { CreateMaterialRequest, MaterialDto, UpdateMaterialRequest } from './models';

export function toCreateMaterialPayload(form: Partial<MaterialDto>): CreateMaterialRequest {
  return {
    code: normalizeCode(form.code!),
    name: form.name!.trim(),
    categoryCode: normalizeCodeOptional(form.categoryCode),
    materialGroupId: form.materialGroupId || undefined,
    unitCode: normalizeCode(form.unitCode!),
    description: form.description?.trim() || undefined,
    standardCost: form.standardCost ?? 0,
    listPrice: form.listPrice,
    salesTaxRate: form.salesTaxRate,
    minStockLevel: form.minStockLevel,
    maxStockLevel: form.maxStockLevel,
    accountCode: normalizeCodeOptional(form.accountCode),
  };
}

export function toUpdateMaterialPayload(form: Partial<MaterialDto>): UpdateMaterialRequest {
  return {
    name: form.name!.trim(),
    categoryCode: normalizeCodeOptional(form.categoryCode),
    materialGroupId: form.materialGroupId || undefined,
    unitCode: normalizeCode(form.unitCode!),
    description: form.description?.trim() || undefined,
    standardCost: form.standardCost ?? 0,
    listPrice: form.listPrice,
    salesTaxRate: form.salesTaxRate,
    minStockLevel: form.minStockLevel,
    maxStockLevel: form.maxStockLevel,
    accountCode: normalizeCodeOptional(form.accountCode),
    isActive: form.isActive ?? true,
  };
}
